input.command:
bash -c "python3 -c '
import json
from collections import Counter, defaultdict

with open(\"/tmp/tickets.json\") as f:
    tickets = json.load(f)
with open(\"/tmp/orders2.json\") as f:
    orders = json.load(f)
with open(\"/tmp/products2.json\") as f:
    products = json.load(f)

product_map = {p[\"id\"]: p[\"name\"] for p in products}

user_tickets = defaultdict(list)
for t in tickets:
    user_tickets[t[\"user_id\"]].append(t)

product_user_tickets = defaultdict(list)

for order in orders:
    if order[\"status\"] in (\"failed\", \"refunded\") or order.get(\"flagged\"):
        user_id = order[\"user_id\"]
        if user_id in user_tickets:
            for pid in order.get(\"product_ids\", []):
                for t in user_tickets[user_id]:
                    product_user_tickets[pid].append({
                        \"ticket_id\": t[\"id\"],
                        \"ticket_subject\": t[\"subject\"],
                        \"order_id\": order[\"id\"],
                        \"order_status\": order[\"status\"],
                        \"flagged\": order.get(\"flagged\", False),
                        \"user_id\": user_id
                    })

product_ticket_count = Counter()
for pid, links in product_user_tickets.items():
    distinct_tickets = set(l[\"ticket_id\"] for l in links)
    product_ticket_count[pid] = len(distinct_tickets)

for pid, count in product_ticket_count.most_common(20):
    pname = product_map.get(pid, \"UNKNOWN\")
    print(f\"{pid} ({pname}): {count} distinct tickets\")
'"

